INSERT INTO `news` (`id`, `title`, `slug`, `category`, `content`, `image`, `source`, `source_url`, `status`, `created_at`) VALUES
(1, 'दुर्गा सप्तशती फाउंडेशन के 1 साल पर संध्या सिंह, पारुल गुप्ता व अनन्या सिंह ने झुग्गी बस्ती के बच्चों संग जश्न मनाया।', 'education-initiative-launch', 'Education', 'संवाददाता बृजेश कुमार\r\n\r\nदुर्गा सप्तशती फाउंडेशन की संचालक और समाजसेवी संध्या सिंह ने ‘दुर्गा सप्तशती फाउंडेशन’ के पूरे एक साल होने के खुशी में झुग्गी बस्ती के बच्चों के साथ जश्न मनाया गया जिसमें बच्चों द्वारा रंगारंग कार्यक्रम की आयोजन किया गया बच्चों ने डांस, गायन खेल आदि कार्यक्रम किये जिसमें बच्चों को मंच दिखाने का अवसर भी मिला तथा उनको पुरस्कार भी दिए गए।\r\n\r\nआपको बता दें कि पूरे एक साल से संस्था ने जरूरतमंद महिलाओं व बालिकाओं के लिए सिलाई और बच्चों को एक क्लासरूम बनाकर पढ़ाया जिसमें जैसे अंग्रेजी, गणित आदि विषय पढ़ाए जाते हैं और उनकी बेटी अनन्या सिंह भी मिलकर बच्चों को शिक्षा देने का काम कर रही हैं।\r\n\r\nवह बहुत ही सराहनीय कार्य है संस्था की डायरेक्टर पारुल गुप्ता व कोषाध्यक्ष अनन्या सिंह, विष्णु कुमार अजीत कुमार लालचंद का भी बहुत सहयोग मिल रहा है।\r\n\r\nवैसे आपको जानकर आश्चर्य होगा कि यह संस्था केवल 1 साल पहले ही जुड़ी है लेकिन हमेशा से ही लोगों की मदद करती चली आ रही है। लॉकडाउन हो या उससे पहले वह हमेशा से ही झुग्गी बस्तियों में जाकर राशन, कपड़े, दवाइयां फल आदि वितरित करती रही है।\r\n\r\nउनके इन कार्यों को देखते हुए दुर्गा सप्तशती फाउंडेशन संस्था को सम्मानित किया गया जिससे वह और मेहनत से लोगों की मदद कर सकें। इसी कड़ी में ‘दुर्गा सप्तशती फाउंडेशन’ से जुड़ी सविता शर्मा फाउंडेशन पूरी दिल्ली में लोगों की मदद करने के लिए तैयार है।', 'news_1774936386.jpg', '', '', 'published', '2026-03-31 04:47:47'),
(2, 'दुर्गा सरस्वती फाउंडेशन ने सेल्फ डिफेंस सिख चुके बच्चों को दिए सर्टिफिकेट देकर', 'winter-relief-kits-2025', 'Community', 'दिनांक 1 आज दिन के न्यूटी गार्डन श्याम विहार नजफगढ़ में दुर्गा महासंघ फाउंडेशन को फाउंडर संध्या सिंह डायरेक्टर पारुल गुप्ता चांदेरश्वर अग्रवाल निधि के अपने सभी सहयोगियों के साथ मिलकर सेल्फ डिफेंस सर्टिफिकेट वितरित किए जिसमें झांसा राईड जान्हवी गुप्ता को मुख्य अतिथि के रूप में में मौजूद रहे उनका फूलों का गुलदस्ता देकर स्वागत किया गया आपको बता दें कि संध्या सिंह काफी समय से समाज महिलाओं बच्चियों के लिए काम कर रही हैं जिसमें महिलाओं को आत्मनिर्भर और सेल्फ डिफेंस को सीखने के लिए प्रशिक्षण दिया जाता है। जिसके द्वारा पुलिस भी बच्चा पूरी तरह से सहयोग कर रही है साथ ही यह बताया जा रहा है कि सेल्फ डिफेंस के साथ बच्चियों को शिक्षा देने का काम भी उनकी टीम कर रही है आज जो बच्चियां यहां सेल्फ डिफेंस को सीख रही हैं उनसे पूछा कि अपने सुरक्षा को कैसे सुनिश्चित कर पाएं?\r\nराईड बच्चों को सर्टिफिकेट देकर सम्मानित किया गया जिसमें दिल्ली पुलिस ने अपना सहयोग दिया।\r\nउनका संस्था अपनी को कार्यक्रम में बच्चियों को सेल्फ डिफेंस और डांस कराटे का करतब दिखाया संस्था सिंह और राईड जान्हवी गुप्ता ने अपने हाथों से सभी सर्टिफिकेट वितरित किए सर्टिफिकेट पाकर बच्चियों के चेहरे मुस्कान से खिला उठे आपको बता दें कि जो कार्य दुर्गा महासंघ फाउंडेशन कर रहा है वह बहुत ही सराहनीय कार्य है', 'news_1774937204.jpg', '', '', 'published', '2026-03-31 04:47:47'),
(3, 'Letter of  Appreciation', 'yoga-day-2025-celebration', 'Appreciation', 'On the occasion of 75th anniversary of Indian Independence, “Azadi Ka Amrit Mahotsav” is being celebrated by Dwarka District Police by participating in various competitions like “Rangoli”, “Deshbhakti Geet” and “Lori” organized by Ministry of Culture, Government of India. To achieve the set target of uploading of entries of these events on the govt. portal, Dwarka District called all its helping hands to come forward to participate in the event.\r\n\r\nMs. Sandhya Singh, Coordinator, NGO, Durga Saptashati Foundation, Sec. 17, Dwarka, New Delhi came forward and motivated the students of her organization to actively participate in the competitions on behalf of Dwarka District Police and uploaded the pictures of the events on the govt. portal for further recognition. With her immense support, Dwarka District successfully achieved the set target within stipulated time.\r\n\r\nOn behalf of Dwarka District Police, I appreciate your efforts in this regard and wish you all success in future.', 'news_1774937010.jpg', '', '', 'published', '2026-03-31 04:47:47');

